PREFIX : <http://ambrosia.example.org/construction#>
PREFIX p: <http://ambrosia.example.org/construction/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?governmentagency ?regulatoryboard ?engineeringproject WHERE {
  ?boards a :Boards .
  ?boards p:GovernmentAgency ?governmentagency .
  ?boards p:RegulatoryBoard ?regulatoryboard .
  ?boards p:EngineeringProject ?engineeringproject .
} }
  component: { SELECT ?regulatoryboard ?engineeringproject WHERE {
  ?boards a :Boards .
  ?boards p:RegulatoryBoard ?regulatoryboard .
  ?boards p:EngineeringProject ?engineeringproject .
} }
  component_2: { SELECT ?governmentagency ?engineeringproject WHERE {
  ?boards a :Boards .
  ?boards p:GovernmentAgency ?governmentagency .
  ?boards p:EngineeringProject ?engineeringproject .
} }
}
